import{_ as t,c as e,o as r,a4 as a}from"./chunks/framework.HaEZziQ1.js";const h=JSON.parse('{"title":"Nuxt3笔记","description":"","frontmatter":{},"headers":[],"relativePath":"Document/前端主流开发框架/Vue/Vue服务端渲染/Nuxt3笔记.md","filePath":"Document/前端主流开发框架/Vue/Vue服务端渲染/Nuxt3笔记.md","lastUpdated":1709668918000}'),u={name:"Document/前端主流开发框架/Vue/Vue服务端渲染/Nuxt3笔记.md"},n=a('<h1 id="nuxt3笔记" tabindex="-1">Nuxt3笔记 <a class="header-anchor" href="#nuxt3笔记" aria-label="Permalink to &quot;Nuxt3笔记&quot;">​</a></h1><p>Nuxt3 是一个基于 Vue3 的服务器端渲染（SSR）框架，它可以帮助你快速构建服务端渲染的 Vue 应用程序，开箱即用、更新快速，是一款可用于各种项目上面的优秀框架。</p><p>Nuxt3 的官网地址是：<a href="https://nuxt.com/%EF%BC%8C%E5%8F%AF%E4%BB%A5%E5%9C%A8%E8%BF%99%E9%87%8C%E4%BA%86%E8%A7%A3" target="_blank" rel="noreferrer">https://nuxt.com/，可以在这里了解</a> Nuxt3 的特性、文档、博客、社区等信息。</p><p>Nuxt3 的开源地址是：<a href="https://nuxt.com/v3" target="_blank" rel="noreferrer">https://github.com/nuxt/framework</a>，你可以在这里查看 Nuxt3 的源码、贡献者、许可证、问题、讨论等信息。</p><p>如果想了解更多关于 Nuxt3 的内容，你可以参考以下的一些资源：</p><ul><li><a href="https://thecodingpro.com/courses/nuxt3" target="_blank" rel="noreferrer">Announcing 3.0 · Nuxt Blog</a>：这篇博客文章介绍了 Nuxt3 的发布情况，包括 Nuxt3 的特点、API 稳定性、浏览器和 Node.js 支持、社区贡献、未来计划等。</li><li><a href="https://nuxt.com/blog/nuxt3-rc" target="_blank" rel="noreferrer">Nuxt3 高效入门全攻略 - TheCodingPro</a>：这是一个 Nuxt3 的在线课程，涵盖了 Nuxt3 的基础知识、路由和布局、数据获取、SEO 和元标签、中间件、状态管理、过渡、错误处理、层、服务器路由、自动导入等内容。</li><li><a href="https://nuxt.com/blog/nuxt3-rc" target="_blank" rel="noreferrer">Announcing Nuxt 3 Release Candidate · Nuxt Blog</a>：这篇博客文章介绍了 Nuxt3 的候选版本，包括 Nuxt3 的新服务器引擎、混合渲染、模块化、部署、迁移等内容。</li></ul><p>​</p>',7),o=[n];function x(c,l,s,_,p,i){return r(),e("div",null,o)}const d=t(u,[["render",x]]);export{h as __pageData,d as default};
